INSERT INTO scenarios (id, slug, category, title, description) VALUES
('14b5b850-742d-4295-982f-6bffe8f5920a','v4-backtest-mirage-kc8dz9','trading','Backtest mirage (trading)','Live results are running badly behind the backtest that justified the strategy. Turning it off admits months were wasted; leaving it on burns money to defend a model. The clock is running.'),
('8f6bf9a2-d49d-43a8-97f6-9cc90e09b547','v4-funding-flip-c1v3kn','trading','Funding flip (trading)','The perpetual funding rate on your position just flipped hard against you. Holding now costs real money by the hour; closing locks a loss that might have been temporary.'),
('f7268749-7039-4d04-9b75-d7c26cd12afd','v4-funding-flip-125t9sf','trading','Funding flip II (trading)','The perpetual funding rate on your position just flipped hard against you. Holding now costs real money by the hour; closing locks a loss that might have been temporary. The clock is running.'),
('08c7ad03-05ff-4211-9476-73cbe46108eb','v4-airdrop-lockup-h6zq2e','trading','Airdrop lockup (trading)','A token you were airdropped unlocks today at 54% above your mental sell price — but everyone else unlocks today too, and the order book is already sagging. The clock is running.'),
('25cdcc9a-ed12-4871-ba60-1138de0d4400','v4-airdrop-lockup-1hw06gt','trading','Airdrop lockup II (trading)','A token you were airdropped unlocks today at 35% above your mental sell price — but everyone else unlocks today too, and the order book is already sagging.'),
('c86392c7-353c-4a42-961f-e04563fee888','v4-oracle-divergence-63bca4','trading','Oracle divergence (trading)','Two price feeds you rely on disagree by 40% during a fast move. One is stale, one is lying, and your liquidation logic listens to only one of them. There is no clean option.'),
('364765e7-6827-40e5-9e37-87ff51b1435a','v4-oracle-divergence-1bt2d6f','trading','Oracle divergence II (trading)','Two price feeds you rely on disagree by 46% during a fast move. One is stale, one is lying, and your liquidation logic listens to only one of them.'),
('ec761c5e-6066-4096-a41f-5c50415523e1','v4-quiet-delisting-notice-zfr8xt','trading','Quiet delisting notice (trading)','An exchange quietly posts that a name you hold goes delisted in 10 days. Liquidity will only get worse from here, but the forced-seller discount is already brutal. Nobody senior is reachable.'),
('4d93e588-6ab6-46f7-b372-ba3c41008e65','v4-quiet-delisting-notice-1jzlpgd','trading','Quiet delisting notice II (trading)','An exchange quietly posts that a name you hold goes delisted in 10 days. Liquidity will only get worse from here, but the forced-seller discount is already brutal. The clock is running.'),
